// Get the raw output
let text = $json.output;

// Remove markdown if present
text = text.replace(/```json/g, "").replace(/```/g, "").trim();

// Convert escaped characters
text = text
  .replace(/\\n/g, "\n")
  .replace(/\\"/g, '"')
  .replace(/\\\\/g, "\\");

// Keep only the JSON object
const start = text.indexOf("{");
const end = text.lastIndexOf("}");

if (start === -1 || end === -1) {
  throw new Error("No valid JSON object found in AI output.");
}

text = text.substring(start, end + 1);

let report;

try {
  report = JSON.parse(text);
} catch (err) {  throw new Error(
    `Invalid JSON returned by AI.\n\n${err.message}\n\nLast 500 chars:\n${text.slice(-500)}`
  );
}

function list(arr) {
  if (!Array.isArray(arr) || arr.length === 0) return "Not Available";
  return arr.map(i => `• ${i}`).join("\n");
}

const message = `🤖 AI Resume Analysis Report

👤 Candidate: ${report.candidate_name}
💼 Job Role: ${report.job_title}
🏢 Company: ${report.company}

━━━━━━━━━━━━━━━━━━

🎯 ATS Score: ${report.ats_score.overall}/100

• Skills: ${report.ats_score.skills}/100
• Experience: ${report.ats_score.experience}/100
• Education: ${report.ats_score.education}/100
• Projects: ${report.ats_score.projects}/100
• Keywords: ${report.ats_score.keywords}/100

━━━━━━━━━━━━━━━━━━

📝 Summary

${report.ats_score.explanation}

━━━━━━━━━━━━━━━━━━

✅ Matched Skills

${list(report.skills.matched)}

━━━━━━━━━━━━━━━━━━

❌ Missing Skills

${list(report.skills.missing)}

━━━━━━━━━━━━━━━━━━

💪 Strengths

${list(report.strengths)}

━━━━━━━━━━━━━━━━━━

⚠️ Weaknesses

${list(report.weaknesses)}

━━━━━━━━━━━━━━━━━━

🏁 Final Verdict

Decision: ${report.final_verdict.decision}
Confidence: ${report.final_verdict.confidence}%

Reason:
${report.final_verdict.reason}`;

return {
    json: {
      message
    }
  };
